INSERT INTO announcements (id, sender_id, title, content, create_time) VALUES (UUID(), '409e0852-75d5-11f1-8f13-d8242a668460', '宠物领养流程更新公告', '平台领养申请流程已优化，申请人需完善居住环境、经济情况信息，提交后1-3个工作日完成人工审核。', UNIX_TIMESTAMP() * 1000);
INSERT INTO announcements (id, sender_id, title, content, create_time) VALUES (UUID(), '409e0852-75d5-11f1-8f13-d8242a668460', '线下领养开放日活动通知', '本周六9:00-17:00救助站举办线下领养活动，到场可现场对接宠物，简化审核步骤。', UNIX_TIMESTAMP() * 1000);
INSERT INTO announcements (id, sender_id, title, content, create_time) VALUES (UUID(), '409e0852-75d5-11f1-8f13-d8242a668460', '宠物疫苗驱虫优惠通知', '联合合作宠物医院推出福利，已领养宠物凭领养记录可享疫苗、体内外驱虫8折优惠。', UNIX_TIMESTAMP() * 1000);
INSERT INTO announcements (id, sender_id, title, content, create_time) VALUES (UUID(), '409e0852-75d5-11f1-8f13-d8242a668460', '服务器临时维护通知', '下周三00:00-06:00系统维护，期间无法提交领养申请、查看宠物与公告内容。', UNIX_TIMESTAMP() * 1000);
INSERT INTO announcements (id, sender_id, title, content, create_time) VALUES (UUID(), '409e0852-75d5-11f1-8f13-d8242a668460', '恶意弃养处罚规则公示', '领养后无故弃养、虐待宠物用户将永久拉黑，不再受理任何领养申请，宠物统一回收救助。', UNIX_TIMESTAMP() * 1000);
INSERT INTO announcements (id, sender_id, title, content, create_time) VALUES (UUID(), '409e0852-75d5-11f1-8f13-d8242a668460', '爱心物资捐赠通道开启', '站内宠物粮食、猫砂、常用药品库存紧缺，线上平台与线下站点均可捐赠，物资使用明细每月公示。', UNIX_TIMESTAMP() * 1000);
INSERT INTO announcements (id, sender_id, title, content, create_time) VALUES (UUID(), '409e0852-75d5-11f1-8f13-d8242a668460', '幼龄宠物饲养科普提醒', '未满3个月幼宠不可喂食人食，专用幼宠粮少食多餐，注意保暖，腹泻呕吐需及时就医。', UNIX_TIMESTAMP() * 1000);
INSERT INTO announcements (id, sender_id, title, content, create_time) VALUES (UUID(), '409e0852-75d5-11f1-8f13-d8242a668460', '节假日审核时效说明', '法定节假日工作人员轮休，领养申请审核延迟2-3天，紧急情况可联系在线客服登记加急。', UNIX_TIMESTAMP() * 1000);
INSERT INTO announcements (id, sender_id, title, content, create_time) VALUES (UUID(), '409e0852-75d5-11f1-8f13-d8242a668460', '走失宠物寻宠板块上线', '平台新增寻宠公告专区，丢失宠物的主人可免费发布信息，填写宠物特征、丢失地点与联系方式。', UNIX_TIMESTAMP() * 1000);
INSERT INTO announcements (id, sender_id, title, content, create_time) VALUES (UUID(), '409e0852-75d5-11f1-8f13-d8242a668460', '长期志愿者招募公告', '救助站持续招募志愿者，负责宠物喂养、笼舍清洁、线下活动协助，有意者前往个人中心提交报名表单。', UNIX_TIMESTAMP() * 1000);
INSERT INTO announcements (id, sender_id, title, content, create_time) VALUES (UUID(), '409e0852-75d5-11f1-8f13-d8242a668460', '宠物绝育补贴政策说明', '领养满90天的宠物可申请绝育补贴，凭领养协议前往合作医院，手术费用报销50%，单宠仅限一次。', UNIX_TIMESTAMP() * 1000);
INSERT INTO announcements (id, sender_id, title, content, create_time) VALUES (UUID(), '409e0852-75d5-11f1-8f13-d8242a668460', '系统新版本功能升级说明', '本次更新新增宠物收藏、申请进度实时查询、在线客服聊天功能，图片上传速度大幅优化。', UNIX_TIMESTAMP() * 1000);
INSERT INTO announcements (id, sender_id, title, content, create_time) VALUES (UUID(), '409e0852-75d5-11f1-8f13-d8242a668460', '暴雨天气线下领养活动取消', '受持续性暴雨影响，原周日线下领养活动取消，新活动举办时间将另行发布公告通知。', UNIX_TIMESTAMP() * 1000);
INSERT INTO announcements (id, sender_id, title, content, create_time) VALUES (UUID(), '409e0852-75d5-11f1-8f13-d8242a668460', '老年宠物专属领养福利', '5岁以上老年宠物领养免全部手续费用，赠送全年基础驱虫套餐，适合时间充足、性格温和饲养者。', UNIX_TIMESTAMP() * 1000);
INSERT INTO announcements (id, sender_id, title, content, create_time) VALUES (UUID(), '409e0852-75d5-11f1-8f13-d8242a668460', '城市大型犬饲养规范提醒', '按照城市养犬管理条例，大型犬不可长期笼养，领养大型犬需提供宽敞住房证明，不达标申请直接驳回。', UNIX_TIMESTAMP() * 1000);
